from langchain_core.tools import tool

@tool
def request_handoff(
    handoff_to: Literal["legal", "financial", "technical", "writer"],
    work_done: str,
    reason: str,
    next_steps: str,
) -> str:
    """Call this when you need to transfer the task to a specialist.
    Only call it once — the specialist will take over immediately."""
    return f"Handoff requested to {handoff_to}"

research_llm_with_tools = llm.bind_tools([request_handoff])

def research_agent_v2(state: TaskState) -> dict:
    response = research_llm_with_tools.invoke([
        {"role": "system", "content": "Research the task. Call request_handoff if you need a specialist."},
        {"role": "user", "content": state["original_query"]},
    ])

    handoff = None
    for call in (response.tool_calls or []):
        if call["name"] == "request_handoff":
            handoff = call["args"]
            break

    return {
        "handoff": handoff,
        "work_log": state["work_log"] + [response.content or ""],
    }

def format_work_log(work_log: list[str]) -> str:
    if not work_log:
        return "No prior work."
    return "\n".join(f"[{i+1}] {entry}" for i, entry in enumerate(work_log))

def writer_agent(state: TaskState) -> dict:
    context = format_work_log(state["work_log"])
    prompt = f"""All prior research and analysis:\n{context}\n\n
Original request: {state["original_query"]}

Write a clear, professional summary that integrates all findings."""

    response = llm.invoke([
        {"role": "system", "content": "You are a technical writer. Synthesise the work log into a final report."},
        {"role": "user", "content": prompt},
    ])
    return {
        "final_response": response.content,
        "work_log": state["work_log"] + [f"writer: produced final report"],
    }

class TaskStateWithHops(TaskState):
    hop_count: int

MAX_HOPS = 4

def route_with_hop_guard(state: TaskStateWithHops) -> str:
    if state["hop_count"] >= MAX_HOPS:
        # Force termination — log a warning and return what we have
        return "END"
    if state.get("handoff"):
        return state["handoff"].get("handoff_to", "END")
    return "END"

def increment_hop(state: TaskStateWithHops) -> dict:
    return {"hop_count": state["hop_count"] + 1}

# Add hop increment as a pass-through after each agent node
builder.add_node("increment_hop", increment_hop)
# Wire: research → increment_hop → conditional edge
builder.add_edge("research", "increment_hop")
builder.add_conditional_edges("increment_hop", route_with_hop_guard, ...)
